-- Inserção de 30 questões de Fundamentos de Enfermagem (Consolidado como Fundamentos e SAE)
INSERT INTO public.questions (id, category, banca, question, options, "correctAnswer", explanation) VALUES
(11001, 'Fundamentos e SAE', 'VUNESP', 'Ao aferir a pressão arterial de um paciente adulto, o técnico de enfermagem deve certificar-se de que a largura da câmara inflável do manguito corresponde a qual porcentagem da circunferência do braço?', 
'[{"id": "A", "text": "20%"}, {"id": "B", "text": "40%"}, {"id": "C", "text": "60%"}, {"id": "D", "text": "80%"}, {"id": "E", "text": "100%"}]', 
'B', 'Segundo as VII Diretrizes Brasileiras de Hipertensão, a largura do manguito deve corresponder a 40% da circunferência do braço e o comprimento a 80%.'),

(11002, 'Fundamentos e SAE', 'FGV', 'Qual é a terminologia correta para designar uma respiração rápida e superficial, comum em estados de choque ou ansiedade?', 
'[{"id": "A", "text": "Bradipneia"}, {"id": "B", "text": "Eupneia"}, {"id": "C", "text": "Taquipneia"}, {"id": "D", "text": "Apneia"}, {"id": "E", "text": "Ortopneia"}]', 
'C', 'Taquipneia é o aumento da frequência respiratória acima dos valores de referência (em adultos, > 20 irpm).'),

(11003, 'Fundamentos e SAE', 'IBFC', 'Durante a administração de medicamentos por via intramuscular no músculo deltoide, qual o volume máximo recomendado para evitar distensão tecidual e dor intensa?', 
'[{"id": "A", "text": "0,5 ml"}, {"id": "B", "text": "1,0 ml"}, {"id": "C", "text": "3,0 ml"}, {"id": "D", "text": "5,0 ml"}, {"id": "E", "text": "10 ml"}]', 
'B', 'Embora literaturas citem até 2ml, o recomendado para segurança e conforto no deltoide é de 0,5 a 1,0 ml.'),

(11004, 'Fundamentos e SAE', 'FGV', 'O pulso que se apresenta fraco, de pequena amplitude e que desaparece facilmente à pressão dos dedos é denominado:', 
'[{"id": "A", "text": "Célere"}, {"id": "B", "text": "Dicrótico"}, {"id": "C", "text": "Filiforme"}, {"id": "D", "text": "Rítmico"}, {"id": "E", "text": "Pleno"}]', 
'C', 'O pulso filiforme é característico de estados de choque e desidratação, indicando baixo volume sistólico.'),

(11005, 'Fundamentos e SAE', 'VUNESP', 'Para a realização de uma Sondagem Vesical de Demora (SVD) em um paciente do sexo masculino, a fixação da sonda deve ser feita preferencialmente em qual região?', 
'[{"id": "A", "text": "Face interna da coxa"}, {"id": "B", "text": "Face externa da coxa"}, {"id": "C", "text": "Região hipogástrica (abdome inferior)"}, {"id": "D", "text": "Região inguinal"}, {"id": "E", "text": "Lateral do quadril"}]', 
'C', 'No homem, a fixação no abdome inferior evita a pressão constante na junção penoescrotal, prevenindo fístulas e lesões uretrais.'),

(11006, 'Fundamentos e SAE', 'CESGRANRIO', 'Qual é a posição de escolha para um paciente que apresenta dificuldade respiratória grave (ortopneia)?', 
'[{"id": "A", "text": "Trendelenburg"}, {"id": "B", "text": "Sims"}, {"id": "C", "text": "Fowler (45º a 60º)"}, {"id": "D", "text": "Decúbito Ventral"}, {"id": "E", "text": "Genupeitoral"}]', 
'C', 'A posição de Fowler facilita a expansão pulmonar e o uso da musculatura acessória, aliviando a dispneia.'),

(11007, 'Fundamentos e SAE', 'EBSERH', 'Na técnica de banho no leito, a ordem correta de higienização deve ser:', 
'[{"id": "A", "text": "Dos pés para a cabeça"}, {"id": "B", "text": "Da região genital para a face"}, {"id": "C", "text": "Das áreas mais limpas para as mais contaminadas"}, {"id": "D", "text": "Das áreas mais contaminadas para as mais limpas"}, {"id": "E", "text": "Aleatória, conforme a preferência do paciente"}]', 
'C', 'Para evitar a translocação de microrganismos, o banho deve sempre iniciar pelas áreas mais limpas (rosto, braços) e terminar nas mais contaminadas (genitais, ânus).'),

(11008, 'Fundamentos e SAE', 'FCC', 'A via de administração de medicamentos que oferece a absorção mais lenta e constante, utilizada frequentemente para vacina BCG, é a:', 
'[{"id": "A", "text": "Subcutânea"}, {"id": "B", "text": "Intradérmica"}, {"id": "C", "text": "Intramuscular"}, {"id": "D", "text": "Endovenosa"}, {"id": "E", "text": "Via Oral"}]', 
'B', 'A via intradérmica atinge a derme, onde a vascularização é reduzida, permitindo absorção lenta. Volume máximo: 0,5ml.'),

(11009, 'Fundamentos e SAE', 'AOCP', 'Quantas gotas por minuto são necessárias para administrar 500ml de Soro Fisiológico em 8 horas?', 
'[{"id": "A", "text": "15 gotas/min"}, {"id": "B", "text": "21 gotas/min"}, {"id": "C", "text": "32 gotas/min"}, {"id": "D", "text": "42 gotas/min"}, {"id": "E", "text": "63 gotas/min"}]', 
'B', 'Fórmula: Volume / (Tempo x 3). 500 / (8 x 3) = 500 / 24 = 20,83. Arredondando: 21 gotas/min.'),

(11010, 'Fundamentos e SAE', 'VUNESP', 'Ao realizar o curativo de uma ferida cirúrgica limpa com pontos, a limpeza com soro fisiológico deve ser feita em qual sentido?', 
'[{"id": "A", "text": "Das bordas para o centro da incisão"}, {"id": "B", "text": "De baixo para cima"}, {"id": "C", "text": "Da incisão (meio) para as bordas"}, {"id": "D", "text": "Em movimentos circulares de fora para dentro"}, {"id": "E", "text": "Apenas por compressão sem fricção"}]', 
'C', 'Em feridas limpas, a técnica deve ser do local menos contaminado (a incisão) para o mais contaminado (a pele ao redor).'),

(11011, 'Fundamentos e SAE', 'FGV', 'O local de aplicação intramuscular conhecido como técnica de Hochstetter, considerado o mais seguro por estar livre de grandes vasos e nervos, é o:', 
'[{"id": "A", "text": "Deltóide"}, {"id": "B", "text": "Dorsoglúteo"}, {"id": "C", "text": "Ventroglúteo"}, {"id": "D", "text": "Vasto lateral da coxa"}, {"id": "E", "text": "Reto femoral"}]', 
'C', 'O músculo ventroglúteo é a escolha recomendada para injeções profundas pela ausência de estruturas nobres subjacentes.'),

(11012, 'Fundamentos e SAE', 'IBFC', 'Um paciente apresenta uma ferida com tecido de coloração amarela, úmido e aderido. Este tecido é tecnicamente denominado:', 
'[{"id": "A", "text": "Tecido de Granulação"}, {"id": "B", "text": "Tecido de Epitelização"}, {"id": "C", "text": "Esfacelo ou Fibrina"}, {"id": "D", "text": "Necrose de coagulação"}, {"id": "E", "text": "Biofilme purulento"}]', 
'C', 'O esfacelo é composto por restos celulares e fibrina, indicando a necessidade de desbridamento para a cicatrização evoluir.'),

(11013, 'Fundamentos e SAE', 'FCC', 'Qual o volume máximo de líquido que o tecido subcutâneo de um adulto hígido pode suportar em uma única aplicação?', 
'[{"id": "A", "text": "0,5 ml"}, {"id": "B", "text": "1,5 ml"}, {"id": "C", "text": "3,0 ml"}, {"id": "D", "text": "5,0 ml"}, {"id": "E", "text": "10 ml"}]', 
'B', 'O tecido subcutâneo suporta volumes pequenos, geralmente até 1,5 ml a 2,0 ml.'),

(11014, 'Fundamentos e SAE', 'VUNESP', 'A manobra de auxílio à respiração que consiste em elevar a cabeceira do leito a 90º com o paciente inclinando o tronco sobre uma mesa é a:', 
'[{"id": "A", "text": "Fowler"}, {"id": "B", "text": "Ortopneica"}, {"id": "C", "text": "Trendelenburg"}, {"id": "D", "text": "Genupeitoral"}, {"id": "E", "text": "Litotômica"}]', 
'B', 'A posição ortopneica é a variação máxima da Fowler para pacientes com insuficiência cardíaca ou asma grave.'),

(11015, 'Fundamentos e SAE', 'FGV', 'Qual o principal cuidado de enfermagem ao administrar Potássio (KCl) por via endovenosa?', 
'[{"id": "A", "text": "Administrar em bolus rápido se o paciente estiver parado"}, {"id": "B", "text": "Nunca administrar sem diluição (risco de parada cardíaca)"}, {"id": "C", "text": "Usar apenas veias do dorso da mão"}, {"id": "D", "text": "Manter o frasco protegido da luz"}, {"id": "E", "text": "Aquecer o soro antes da infusão"}]', 
'B', 'O potássio concentrado é letal. Deve ser sempre diluído e infundido lentamente sob monitorização.'),

(11016, 'Fundamentos e SAE', 'IBFC', 'O som ouvido na percussão de áreas que contêm ar, como o pulmão normal, é chamado de:', 
'[{"id": "A", "text": "Macicez"}, {"id": "B", "text": "Submacicez"}, {"id": "C", "text": "Claro Pulmonar (Atimpânico)"}, {"id": "D", "text": "Timpanismo"}, {"id": "E", "text": "Estertor"}]', 
'C', 'O som claro pulmonar resulta da vibração do ar dentro dos alvéolos sadios.'),

(11017, 'Fundamentos e SAE', 'CESGRANRIO', 'Segundo os "13 Certos" da administração de medicamentos, verificar se a medicação prescrita causa alergia ao paciente refere-se ao:', 
'[{"id": "A", "text": "Medicamento Certo"}, {"id": "B", "text": "Paciente Certo"}, {"id": "C", "text": "Resposta Certa"}, {"id": "D", "text": "Ação Certa"}, {"id": "E", "text": "Registro Certo"}]', 
'C', 'A Resposta Certa envolve monitorar efeitos adversos e alergias após a administração.'),

(11018, 'Fundamentos e SAE', 'VUNESP', 'Qual o ângulo de inserção da agulha para uma injeção subcutânea em um paciente magro, utilizando agulha de 13x4,5mm?', 
'[{"id": "A", "text": "15 graus"}, {"id": "B", "text": "45 graus"}, {"id": "C", "text": "90 graus"}, {"id": "D", "text": "10 graus"}, {"id": "E", "text": "25 graus"}]', 
'B', 'Em pacientes magros ou com pouca gordura, usa-se o ângulo de 45º para evitar atingir o músculo.'),

(11019, 'Fundamentos e SAE', 'FGV', 'A lavagem das mãos com água e sabão comum é indicada preferencialmente quando:', 
'[{"id": "A", "text": "As mãos estão visivelmente sujas"}, {"id": "B", "text": "Após tocar no leito do paciente"}, {"id": "C", "text": "Antes de calçar luvas estéreis"}, {"id": "D", "text": "Ao chegar no plantão"}, {"id": "E", "text": "Após manusear exames de papel"}]', 
'A', 'O álcool em gel substitui a lavagem em quase todos os cenários, exceto quando há sujidade visível ou contato com esporos.'),

(11020, 'Fundamentos e SAE', 'IBFC', 'Como é denominada a alteração do pulso caracterizada por um batimento forte seguido de um fraco, em ritmo regular?', 
'[{"id": "A", "text": "Pulso Dicrótico"}, {"id": "B", "text": "Pulso Alternante"}, {"id": "C", "text": "Pulso Bigeminado"}, {"id": "D", "text": "Pulso Paradoxal"}, {"id": "E", "text": "Pulso Intermitente"}]', 
'B', 'O pulso alternante indica falência ventricular esquerda grave.'),

(11021, 'Fundamentos e SAE', 'FCC', 'Para prevenir Lesão por Pressão (LPP) em pacientes acamados, a mudança de decúbito deve ocorrer em qual intervalo máximo de tempo?', 
'[{"id": "A", "text": "A cada 1 hora"}, {"id": "B", "text": "A cada 2 horas"}, {"id": "C", "text": "A cada 4 horas"}, {"id": "D", "text": "Uma vez por plantão"}, {"id": "E", "text": "Apenas se o paciente solicitar"}]', 
'B', 'O protocolo padrão de prevenção de LPP estabelece o reposicionamento a cada 2 horas.'),

(11022, 'Fundamentos e SAE', 'VUNESP', 'Na aferição da temperatura axilar, o termômetro deve permanecer em contato com a pele por quanto tempo, em média, para garantir a precisão?', 
'[{"id": "A", "text": "30 segundos"}, {"id": "B", "text": "1 minuto"}, {"id": "C", "text": "3 a 5 minutos"}, {"id": "D", "text": "10 minutos"}, {"id": "E", "text": "Até o paciente sentir calor"}]', 
'C', 'A temperatura axilar requer um tempo maior de equilíbrio térmico (3 a 5 min) comparada à oral ou timpânica.'),

(11023, 'Fundamentos e SAE', 'FGV', 'Qual é a finalidade da técnica de "Recuo da Agulha" ou "Aspiração" antes de injetar uma medicação intramuscular?', 
'[{"id": "A", "text": "Verificar se a agulha está no osso"}, {"id": "B", "text": "Garantir que não atingiu um vaso sanguíneo"}, {"id": "C", "text": "Diminuir a pressão da injeção"}, {"id": "D", "text": "Verificar a viscosidade do líquido"}, {"id": "E", "text": "Retirar o ar da seringa"}]', 
'B', 'A aspiração previne a injeção acidental de fármacos oleosos ou suspensões na corrente sanguínea.'),

(11024, 'Fundamentos e SAE', 'IBFC', 'O mnemônico utilizado para medir a sonda nasogástrica é:', 
'[{"id": "A", "text": "Nariz - Orelha - Umbigo"}, {"id": "B", "text": "Boca - Orelha - Xifoide"}, {"id": "C", "text": "Nariz - Orelha - Apêndice Xifoide"}, {"id": "D", "text": "Testa - Queixo - Xifoide"}, {"id": "E", "text": "Orelha - Nariz - Estômago"}]', 
'C', 'Medida padrão: Ponta do nariz ao lobo da orelha e desta ao apêndice xifoide.'),

(11025, 'Fundamentos e SAE', 'EBSERH', 'Qual o desinfetante de escolha para a antissepsia da pele antes de uma punção venosa periférica?', 
'[{"id": "A", "text": "Álcool 70%"}, {"id": "B", "text": "PVPI Degermante"}, {"id": "C", "text": "Água Oxigenada"}, {"id": "D", "text": "Hipoclorito de Sódio"}, {"id": "E", "text": "Éter"}]', 
'A', 'O álcool a 70% (líquido ou swab) é o padrão para procedimentos invasivos simples.'),

(11026, 'Fundamentos e SAE', 'VUNESP', 'Um paciente apresenta febre intermitente, onde a temperatura volta ao normal pelo menos uma vez em 24 horas. Este padrão é chamado de:', 
'[{"id": "A", "text": "Febre Contínua"}, {"id": "B", "text": "Febre Remitente"}, {"id": "C", "text": "Febre Intermitente"}, {"id": "D", "text": "Febre Recurrente"}, {"id": "E", "text": "Hiperpirexia"}]', 
'C', 'Na febre intermitente, há oscilações onde a temperatura atinge níveis normais diariamente.'),

(11027, 'Fundamentos e SAE', 'FGV', 'Qual é a profundidade de compressão torácica recomendada para a RCP em adultos, segundo a American Heart Association (2020)?', 
'[{"id": "A", "text": "No máximo 4 cm"}, {"id": "B", "text": "Entre 5 e 6 cm"}, {"id": "C", "text": "Mais de 7 cm"}, {"id": "D", "text": "Apenas 2 cm"}, {"id": "E", "text": "Até sentir as costelas estalarem"}]', 
'B', 'As diretrizes recomendam compressões de 5 a 6 cm (2 a 2,4 polegadas) para garantir a perfusão.'),

(11028, 'Fundamentos e SAE', 'IBFC', 'O exame físico que utiliza a ponta dos dedos para avaliar a textura, temperatura e presença de massas é a:', 
'[{"id": "A", "text": "Inspeção"}, {"id": "B", "text": "Palpação"}, {"id": "C", "text": "Percussão"}, {"id": "D", "text": "Ausculta"}, {"id": "E", "text": "Olfatação"}]', 
'B', 'A palpação utiliza o tato para coletar dados sobre as estruturas corporais.'),

(11029, 'Fundamentos e SAE', 'FCC', 'Qual o termo técnico para a dificuldade de respirar quando o paciente está deitado, melhorando ao sentar ou ficar de pé?', 
'[{"id": "A", "text": "Apneia"}, {"id": "B", "text": "Bradipneia"}, {"id": "C", "text": "Ortopneia"}, {"id": "D", "text": "Trepopneia"}, {"id": "E", "text": "Platipneia"}]', 
'C', 'A ortopneia é um sintoma clássico de insuficiência cardíaca esquerda descompensada.'),

(11030, 'Fundamentos e SAE', 'VUNESP', 'Na escala de Braden, utilizada para avaliar o risco de lesão por pressão, qual pontuação indica um risco maior?', 
'[{"id": "A", "text": "Pontuação 23"}, {"id": "B", "text": "Pontuação 18"}, {"id": "C", "text": "Pontuação 15"}, {"id": "D", "text": "Pontuação 9"}, {"id": "E", "text": "Pontuação 20"}]', 
'D', 'Diferente de outras escalas, na Braden, quanto MENOR a pontuação, MAIOR o risco. Nota 9 indica risco muito alto.');